var e=JSON.parse(`[{"id":"L5_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L6_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"끝났어.","JPN":"終わりよ。","ENG":"It's over.","TWN":"結束了。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L8_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"지금도, 미래에도, 당신의 검술은 여전히 부족하구나.","JPN":"今も未来も、あなたの剣術は未熟なのね。","ENG":"Your swordsmanship is still lacking. In the present or the future, it hasn't changed.","TWN":"不論是現在還是未來，你的劍術都還是不夠好。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"그 정도 실력으론 범 앞에 서 봐야 별 도움이 되지 않을 거야.","JPN":"その程度の腕じゃ、虎に立ち向かったところで大して役に立たないわ。","ENG":"With that level of skill, you'll be no help at all against the Tiger.","TWN":"你這種實力，就算站在老虎面前也幫不上什麼忙。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그대는 강하군.","JPN":"そなたは強いな。","ENG":"You're strong.","TWN":"你很強。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"최고의 스승을 뒀으니까.","JPN":"最高の師匠がいるからね。","ENG":"I had the best teacher.","TWN":"因為我有一個最好的老師。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"내겐 그런 검술 스승이 없었나?","JPN":"某にはそのような師匠がいなかったのか？","ENG":"Did I never have someone to teach me the sword like you?","TWN":"我沒有劍術老師嗎？"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"욕심이 과해. 당신은 이미 물건 만드는 재주가 누구보다 좋잖아.","JPN":"欲張りすぎよ。あなたは物を創る才能に誰よりも恵まれたじゃない。","ENG":"You're being greedy. You've always had a gift for crafting things no one else could.","TWN":"你太貪心囉，你的發明天賦已經比任何人強。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"정작 필요할 때 도움이 못 된다면 그 재주가 다 무슨 소용이지?","JPN":"本当に助けが必要な時役に立たないなら、その才能に何の意味がある？","ENG":"But what good is that gift if it can't help when it matters most?","TWN":"如果只在需要的時候才有用，那這個天賦還有什麼用？"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"그 말은 틀려.","JPN":"とんでもない。","ENG":"That's not true.","TWN":"不對。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"당신은 검만 휘두르지 않았을 뿐, 매 순간 유능한 사람이었어.","JPN":"あなたは剣を握っていないだけで、いつどんな時でも有能な人だったわ。","ENG":"You might not have wielded a sword, but you've always been capable. Every single moment.","TWN":"你雖然沒有揮劍，但在每一個瞬間都是個很有用的人。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"우리가 그 짐승을 잡을 수 있도록 우물을 파고 길을 열어준 것도 당신이었으니까.","JPN":"私たちがあのケモノを討てるようにイドを掘り、道を切り開いてくれたのはあなただもの。","ENG":"It was you who dug the well and cleared the path so we could reach the Beast.","TWN":"是你挖井、開路，我們才能抓住那隻野獸。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SURPRISE"},"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"당신 말처럼 미래에도 세상에 검은 비가 내린다면, 빈 말로도 살기 좋은 세상이라곤 할 수 없겠네.","JPN":"あなたの言う通り、未来でも黒い雨が降っているのなら……お世辞にも住みやすい世界とは言えないわね。","ENG":"If, as you said, black rain still falls in the future, then no one could call that a world worth living in.","TWN":"正如你所說，如果未來世界上還是會下墨雨，那也稱不上是一個好地方。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SURPRISE"},"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"그러니 과거는 나한테 맡기고 돌아가.","JPN":"だから過去は私に任せて、あなたは帰りなさい。","ENG":"So let me handle the past. You go back.","TWN":"所以把過去交給我，你回去吧。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L24_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"돌아가서 당신의 멋진 재주로, 최대한 많은 사람들을 도와줘.","JPN":"帰って、あなたの素敵な才能で、なるべく多くの人を助けてあげて。","ENG":"Use your amazing talent to help as many people as you can.","TWN":"回去，然後用你那出色的天賦，去幫助更多的人。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그걸로 괜찮은 건가?","JPN":"そうなってもいいのか？","ENG":"And you're fine with that?","TWN":"這樣真的好嗎？"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_HATE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L27_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"미련 같은 건 조금도 없다고 말할 수 있나?","JPN":"未練など少しもないと、言い切れるのか？","ENG":"Can you really say you don't have any regrets?","TWN":"你真的沒有一點留戀嗎？"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L30_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"있다고 한들, 타고난 운명인 걸 어쩌겠어.","JPN":"あったとしてもどうにもならないわ。これが運命だもの。","ENG":"Even if I do, what can I do? It's the fate I was born with.","TWN":"就算有，這也是我的宿命，有什麼辦法呢？"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"그러니 당신도, 나도. 각자의 시간에서 최선을 다하는 수 밖에.","JPN":"だからあなたも、私も。それぞれの時間で最善を尽くすしかないわ。","ENG":"So you and I, we each do what we can in our own time.","TWN":"所以，你和我，我們只能在各自的時間裡盡力而為。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"잠깐. 아직 할 말이 끝나지 않았…!","JPN":"待て、まだ話が終わっていな……！","ENG":"Wait. I'm not finis–!","TWN":"等一下。我還沒說完…！"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L38_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"휴우…","JPN":"ふう……","ENG":"*Sigh…*","TWN":"呼…"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"남의 속도 모르고 자꾸 마음을 흔들어 대다니. 눈치 없는 건 여전하네.","JPN":"人の気も知らないで何度も決心が揺らぐようなこと言って。鈍感なのは変わらないのね。","ENG":"Always stirring up my feelings without even knowing. You haven't changed a bit.","TWN":"不知道人家的心意，還一直動搖我。你依舊很遲鈍呢。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"연화.","JPN":"レンカ。","ENG":"Yeonhwa.","TWN":"蓮華。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L42_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"서생이 다음 기슭으로 가는 좌표를 찾았다는구나. 준비가 끝나면 우물로 돌아오거라.","JPN":"ショウが次の麓へ向かう座標を見つけたそうだ。準備が済んだらイドに戻ってこい。","ENG":"Seosaeng found the coordinates to the next ridge. Once you're ready, return to the well.","TWN":"書生找到前往下一個山麓的座標。準備好後就回到井邊來。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"네, 금방 갈게요.","JPN":"はい、すぐ行きます。","ENG":"Got it. I'll be right there.","TWN":"好的，我馬上就來。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"하아- 몸이나 담글까 했는데, 진짜 세수만 하고 가야하잖아.","JPN":"はあ～水浴びしたかったのに、本当に顔を洗う時間しかなくなったじゃない。","ENG":"*Sigh…* I was hoping for a full soak, but I guess I really am just washing my face.","TWN":"真是的，本來想泡個澡的，結果真的只能洗個臉就走。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"말은 그렇게 했지만, 마지막 공격은 아슬아슬했지.","JPN":"ああは言ったけど、最後の攻撃はギリギリだったわ。","ENG":"I said all that, but that last strike was a close one.","TWN":"話是這麼說，但最後的攻擊還是很驚險。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"허술해 보이긴 해도… 뒷심은 있다니까.","JPN":"隙だらけに見えて……底力はあるのよね。","ENG":"He may look sloppy… but he's got grit when it counts.","TWN":"雖然看起來不經意…但後勁十足。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};